(window.webpackJsonp=window.webpackJsonp||[]).push([[302],{584:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {number} n\\n * @return {number}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> numPrimeArrangements = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1000000007</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">countNotPrime</span>(<span class=\\"hljs-params\\">n</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=n;i++){\\n\\t  <span class=\\"hljs-keyword\\">if</span>(i===<span class=\\"hljs-number\\">1</span>){count++;<span class=\\"hljs-keyword\\">continue</span>}\\n\\t  <span class=\\"hljs-keyword\\">if</span>(i===<span class=\\"hljs-number\\">2</span>)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">2</span>;j&lt;=<span class=\\"hljs-built_in\\">Math</span>.sqrt(i);j++){\\n        <span class=\\"hljs-keyword\\">if</span>(i%j===<span class=\\"hljs-number\\">0</span>){count++;<span class=\\"hljs-keyword\\">break</span>}\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> count\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">f</span>(<span class=\\"hljs-params\\">n</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=n;i++){\\n      res=res*i % MOD\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> c=countNotPrime(n)\\n  <span class=\\"hljs-keyword\\">return</span> f(c)*f(n-c) % MOD\\n};\\n</code></pre>\\n"],"titleSlug":"prime-arrangements","hasThinking":false,"content":"<p>\u8bf7\u4f60\u5e2e\u5fd9\u7ed9\u4ece <code>1</code> \u5230 <code>n</code>&nbsp;\u7684\u6570\u8bbe\u8ba1\u6392\u5217\u65b9\u6848\uff0c\u4f7f\u5f97\u6240\u6709\u7684\u300c\u8d28\u6570\u300d\u90fd\u5e94\u8be5\u88ab\u653e\u5728\u300c\u8d28\u6570\u7d22\u5f15\u300d\uff08\u7d22\u5f15\u4ece 1 \u5f00\u59cb\uff09\u4e0a\uff1b\u4f60\u9700\u8981\u8fd4\u56de\u53ef\u80fd\u7684\u65b9\u6848\u603b\u6570\u3002</p>\\n\\n<p>\u8ba9\u6211\u4eec\u4e00\u8d77\u6765\u56de\u987e\u4e00\u4e0b\u300c\u8d28\u6570\u300d\uff1a\u8d28\u6570\u4e00\u5b9a\u662f\u5927\u4e8e 1 \u7684\uff0c\u5e76\u4e14\u4e0d\u80fd\u7528\u4e24\u4e2a\u5c0f\u4e8e\u5b83\u7684\u6b63\u6574\u6570\u7684\u4e58\u79ef\u6765\u8868\u793a\u3002</p>\\n\\n<p>\u7531\u4e8e\u7b54\u6848\u53ef\u80fd\u4f1a\u5f88\u5927\uff0c\u6240\u4ee5\u8bf7\u4f60\u8fd4\u56de\u7b54\u6848 <strong>\u6a21 mod&nbsp;<code>10^9 + 7</code></strong>&nbsp;\u4e4b\u540e\u7684\u7ed3\u679c\u5373\u53ef\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 5\\n<strong>\u8f93\u51fa\uff1a</strong>12\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e3e\u4e2a\u4f8b\u5b50\uff0c[1,2,5,4,3] \u662f\u4e00\u4e2a\u6709\u6548\u7684\u6392\u5217\uff0c\u4f46 [5,2,3,4,1] \u4e0d\u662f\uff0c\u56e0\u4e3a\u5728\u7b2c\u4e8c\u79cd\u60c5\u51b5\u91cc\u8d28\u6570 5 \u88ab\u9519\u8bef\u5730\u653e\u5728\u7d22\u5f15\u4e3a 1 \u7684\u4f4d\u7f6e\u4e0a\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 100\\n<strong>\u8f93\u51fa\uff1a</strong>682289015\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 100</code></li>\\n</ul>\\n"}')}}]);